@namespace sv_92875868f74646c48509ae444c691bd9.Components.JobApplication

<nav class="step-indicator" aria-label="Application steps">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var stepIndex = i;
        var stepNumber = i + 1;
        var status = stepNumber == CurrentStep ? "active"
                   : CompletedSteps.Contains(stepNumber) ? "completed"
                   : "pending";

        <button class="step @status"
                disabled="@(status == "pending")"
                @onclick="() => OnStepClicked.InvokeAsync(stepNumber)"
                aria-current="@(status == "active" ? "step" : null)">
            <span class="step-circle">
                @if (status == "completed")
                {
                    <span class="checkmark">✓</span>
                }
                else
                {
                    @stepNumber
                }
            </span>
            <span class="step-label">@StepNames[stepIndex]</span>
        </button>

        @if (i < StepNames.Length - 1)
        {
            <span class="step-connector @(CompletedSteps.Contains(stepNumber) ? "completed" : "")"></span>
        }
    }
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0;
    margin-bottom: 2rem;
    flex-wrap: wrap;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.4rem;
    background: none;
    border: none;
    cursor: pointer;
    padding: 0.5rem;
    min-width: 6rem;
}

.step.pending {
    cursor: default;
    opacity: 0.45;
}

.step-circle {
    width: 2.2rem;
    height: 2.2rem;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.95rem;
    border: 2px solid #cbd5e1;
    background: #fff;
    color: #64748b;
    transition: all 0.2s;
}

.step.active .step-circle {
    border-color: #2563eb;
    background: #2563eb;
    color: #fff;
}

.step.completed .step-circle {
    border-color: #16a34a;
    background: #16a34a;
    color: #fff;
}

.checkmark {
    font-size: 1.1rem;
}

.step-label {
    font-size: 0.78rem;
    color: #64748b;
    text-align: center;
    white-space: nowrap;
}

.step.active .step-label {
    color: #2563eb;
    font-weight: 600;
}

.step.completed .step-label {
    color: #16a34a;
}

.step-connector {
    width: 2.5rem;
    height: 2px;
    background: #cbd5e1;
    margin-bottom: 1.4rem;
}

.step-connector.completed {
    background: #16a34a;
}

@namespace sv_92875868f74646c48509ae444c691bd9.Components.JobApplication
@using sv_92875868f74646c48509ae444c691bd9.Models

<fieldset class="work-entry-form">
    <legend>Position @Index</legend>

    <div class="form-row">
        <div class="form-group">
            <label>Company Name</label>
            <input type="text" @bind="Entry.Company" @bind:event="oninput"
                   @bind:after="NotifyChanged" placeholder="Company name" />
        </div>
        <div class="form-group">
            <label>Job Title</label>
            <input type="text" @bind="Entry.Title" @bind:event="oninput"
                   @bind:after="NotifyChanged" placeholder="Job title" />
        </div>
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Start Date</label>
            <input type="date" @bind="Entry.StartDate" @bind:after="NotifyChanged" />
        </div>
        <div class="form-group">
            <label>
                <input type="checkbox" @bind="Entry.IsCurrent" @bind:after="OnCurrentChanged" />
                Currently working here
            </label>
            @if (!Entry.IsCurrent)
            {
                <label>End Date</label>
                <input type="date" @bind="Entry.EndDate" @bind:after="NotifyChanged" />
            }
        </div>
    </div>

    <div class="form-group">
        <label>Description</label>
        <textarea rows="3" @bind="Entry.Description" @bind:event="oninput"
                  @bind:after="NotifyChanged" placeholder="Describe your responsibilities..."></textarea>
    </div>

    @if (CanRemove)
    {
        <button type="button" class="btn-remove" @onclick="OnRemove">Remove</button>
    }
</fieldset>

@code {
    [Parameter, EditorRequired] public WorkEntryModel Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private Task NotifyChanged() => OnChanged.InvokeAsync();

    private Task OnCurrentChanged()
    {
        if (Entry.IsCurrent)
            Entry.EndDate = null;
        return NotifyChanged();
    }
}

.work-entry-form {
    border: 1px solid #e2e8f0;
    border-radius: 0.5rem;
    padding: 1.25rem;
    margin-bottom: 1rem;
    background: #f8fafc;
}

.work-entry-form legend {
    font-weight: 600;
    color: #334155;
    padding: 0 0.5rem;
}

.btn-remove {
    background: #fef2f2;
    color: #dc2626;
    border: 1px solid #fecaca;
    padding: 0.35rem 0.75rem;
    border-radius: 0.375rem;
    cursor: pointer;
    font-size: 0.85rem;
    margin-top: 0.5rem;
}

.btn-remove:hover {
    background: #fee2e2;
}

@namespace sv_92875868f74646c48509ae444c691bd9.Components.JobApplication
@using sv_92875868f74646c48509ae444c691bd9.Models

<fieldset class="reference-form">
    <legend>Reference @Index</legend>

    <div class="form-row">
        <div class="form-group">
            <label>Name</label>
            <input type="text" @bind="Reference.Name" @bind:event="oninput"
                   @bind:after="NotifyChanged" placeholder="Full name" />
        </div>
        <div class="form-group">
