    border: 2px solid #cbd5e1;
    background: #fff;
    color: #64748b;
    transition: all 0.2s;
}

.step.active .step-circle {
    border-color: #2563eb;
    background: #2563eb;
    color: #fff;
}

.step.completed .step-circle {
    border-color: #16a34a;
    background: #16a34a;
    color: #fff;
}

.checkmark {
    font-size: 1.1rem;
}

.step-label {
    font-size: 0.78rem;
    color: #64748b;
    text-align: center;
    white-space: nowrap;
}

.step.active .step-label {
    color: #2563eb;
    font-weight: 600;
}

.step.completed .step-label {
    color: #16a34a;
}

.step-connector {
    width: 2.5rem;
    height: 2px;
    background: #cbd5e1;
    margin-bottom: 1.4rem;
}

.step-connector.completed {
    background: #16a34a;
}

