arguments.file_text:
@namespace sv_92875868f74646c48509ae444c691bd9.Components.JobApplication
@using sv_92875868f74646c48509ae444c691bd9.Models

<section class="step-section">
    <h2>Personal Information</h2>

    <div class="form-group">
        <label>Full Name <span class="required">*</span></label>
        <input type="text" @bind="Model.FullName" @bind:event="oninput" placeholder="John Doe" />
        @if (errors.ContainsKey("FullName"))
        {
            <span class="field-error">@errors["FullName"]</span>
        }
    </div>

    <div class="form-group">
        <label>Email <span class="required">*</span></label>
        <input type="email" @bind="Model.Email" @bind:event="oninput" placeholder="john@example.com" />
        @if (errors.ContainsKey("Email"))
        {
            <span class="field-error">@errors["Email"]</span>
        }
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Phone <span class="required">*</span></label>
            <input type="tel" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 555-5555" />
            @if (errors.ContainsKey("Phone"))
            {
                <span class="field-error">@errors["Phone"]</span>
            }
        </div>
        <div class="form-group">
            <label>Address <span class="required">*</span></label>
            <input type="text" @bind="Model.Address" @bind:event="oninput" placeholder="123 Main St, City, State" />
            @if (errors.ContainsKey("Address"))
            {
                <span class="field-error">@errors["Address"]</span>
            }
        </div>
    </div>

    @if (isValidating)
    {
        <p class="validating-message">Validating email…</p>
    }

    <div class="step-actions">
        <button type="button" class="btn-primary" @onclick="HandleNext" disabled="@isValidating">Next</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private Dictionary<string, string> errors = new();
    private bool isValidating;

    private async Task HandleNext()
    {
        errors.Clear();

        if (string.IsNullOrWhiteSpace(Model.FullName))
            errors["FullName"] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(Model.Email))
            errors["Email"] = "Email is required.";
        if (string.IsNullOrWhiteSpace(Model.Phone))
            errors["Phone"] = "Phone is required.";
        if (string.IsNullOrWhiteSpace(Model.Address))
            errors["Address"] = "Address is required.";

        if (errors.Count > 0)
            return;

        if (ValidateEmail is not null)
        {
            isValidating = true;
            StateHasChanged();

            var isValid = await ValidateEmail(Model.Email);
            isValidating = false;

            if (!isValid)
            {
                errors["Email"] = "This email address is not valid.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_92875868f74646c48509ae444c691bd9.Components.JobApplication
@using sv_92875868f74646c48509ae444c691bd9.Models

<section class="step-section">
    <h2>Work History</h2>

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="Entries[index]"
                       Index="@(index + 1)"
                       CanRemove="@(Entries.Count > 1)"
                       OnChanged="StateHasChanged"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn-secondary" @onclick="AddEntry">+ Add Another Position</button>

    @if (showError)
    {
        <p class="field-error">Each position must have at least a company name, title, and start date.</p>
    }

    <div class="step-actions">
        <button type="button" class="btn-outline" @onclick="OnBack">Back</button>
        <button type="button" class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = [];
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private bool showError;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        showError = Entries.Any(e =>
            string.IsNullOrWhiteSpace(e.Company) ||
            string.IsNullOrWhiteSpace(e.Title) ||
            e.StartDate is null);

        if (!showError)
            await OnNext.InvokeAsync();
    }
}

@namespace sv_92875868f74646c48509ae444c691bd9.Components.JobApplication
@using sv_92875868f74646c48509ae444c691bd9.Models

<section class="step-section">
    <h2>References</h2>

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Reference="References[index]"
                       Index="@(index + 1)"
                       CanRemove="@(References.Count > 1)"
                       OnChanged="StateHasChanged"
                       OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn-secondary" @onclick="AddReference">+ Add Reference</button>
    }

    @if (showError)
    {
        <p class="field-error">Each reference must have at least a name and email.</p>
    }

    <div class="step-actions">
        <button type="button" class="btn-outline" @onclick="OnBack">Back</button>
        <button type="button" class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = [];
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private bool showError;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 1)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        showError = References.Any(r =>
            string.IsNullOrWhiteSpace(r.Name) ||
            string.IsNullOrWhiteSpace(r.Email));

        if (!showError)
            await OnNext.InvokeAsync();
    }
}

@namespace sv_92875868f74646c48509ae444c691bd9.Components.JobApplication

<section class="step-section">
    <h2>Cover Letter</h2>

    <div class="form-group">
        <label>Write your cover letter</label>
        <textarea class="cover-letter-input"
                  rows="12"
                  maxlength="@MaxLength"
                  @bind="currentValue"
                  @bind:event="oninput"
                  @bind:after="OnTextChanged"
                  placeholder="Dear Hiring Manager..."></textarea>
        <span class="char-count @(currentValue.Length > MaxLength ? "over-limit" : "")">
            @currentValue.Length / @MaxLength characters
        </span>
    </div>

