<section class="step-section">
    <h2>Personal Information</h2>

    <div class="form-group">
        <label>Full Name <span class="required">*</span></label>
        <input type="text" @bind="Model.FullName" @bind:event="oninput" placeholder="John Doe" />
        @if (errors.ContainsKey("FullName"))
        {
            <span class="field-error">@errors["FullName"]</span>
        }
    </div>

    <div class="form-group">
        <label>Email <span class="required">*</span></label>
        <input type="email" @bind="Model.Email" @bind:event="oninput" placeholder="john@example.com" />
        @if (errors.ContainsKey("Email"))
        {
            <span class="field-error">@errors["Email"]</span>
        }
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Phone <span class="required">*</span></label>
            <input type="tel" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 555-5555" />
            @if (errors.ContainsKey("Phone"))
            {
                <span class="field-error">@errors["Phone"]</span>
            }
        </div>
        <div class="form-group">
            <label>Address <span class="required">*</span></label>
            <input type="text" @bind="Model.Address" @bind:event="oninput" placeholder="123 Main St, City, State" />
            @if (errors.ContainsKey("Address"))
            {
                <span class="field-error">@errors["Address"]</span>
            }
        </div>
    </div>

    @if (isValidating)
    {
        <p class="validating-message">Validating email…</p>
    }

    <div class="step-actions">
        <button type="button" class="btn-primary" @onclick="HandleNext" disabled="@isValidating">Next</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private Dictionary<string, string> errors = new();
    private bool isValidating;

    private async Task HandleNext()
    {
        errors.Clear();

        if (string.IsNullOrWhiteSpace(Model.FullName))
            errors["FullName"] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(Model.Email))
            errors["Email"] = "Email is required.";
        if (string.IsNullOrWhiteSpace(Model.Phone))
            errors["Phone"] = "Phone is required.";
        if (string.IsNullOrWhiteSpace(Model.Address))
            errors["Address"] = "Address is required.";

        if (errors.Count > 0)
            return;

        if (ValidateEmail is not null)
        {
            isValidating = true;
            StateHasChanged();

            var isValid = await ValidateEmail(Model.Email);
            isValidating = false;

            if (!isValid)
            {
                errors["Email"] = "This email address is not valid.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_92875868f74646c48509ae444c691bd9.Components.JobApplication
