<section class="step-section">
    <h2>Cover Letter</h2>

    <div class="form-group">
        <label>Write your cover letter</label>
        <textarea class="cover-letter-input"
                  rows="12"
                  maxlength="@MaxLength"
                  @bind="currentValue"
                  @bind:event="oninput"
                  @bind:after="OnTextChanged"
                  placeholder="Dear Hiring Manager..."></textarea>
        <span class="char-count @(currentValue.Length > MaxLength ? "over-limit" : "")">
            @currentValue.Length / @MaxLength characters
        </span>
    </div>

    @if (showError)
    {
        <p class="field-error">A cover letter is required.</p>
    }

    <div class="step-actions">
        <button type="button" class="btn-outline" @onclick="OnBack">Back</button>
        <button type="button" class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</section>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string currentValue = "";
    private bool showError;

    protected override void OnParametersSet()
    {
        currentValue = CoverLetter;
    }

    private async Task OnTextChanged()
    {
        await CoverLetterChanged.InvokeAsync(currentValue);
    }

    private async Task HandleNext()
    {
        showError = string.IsNullOrWhiteSpace(currentValue);
        if (!showError)
            await OnNext.InvokeAsync();
    }
}
