@namespace sv_92875868f74646c48509ae444c691bd9.Components.JobApplication
@using sv_92875868f74646c48509ae444c691bd9.Models

<section class="step-section">
    <h2>Review & Submit</h2>

    @if (IsSubmitted)
    {
        <div class="confirmation">
            <span class="confirmation-icon">✓</span>
            <h3>Application Submitted!</h3>
            <p>Your application has been received. Your application ID is <strong>#@ApplicationId</strong>.</p>
        </div>
    }
    else
    {
        <div class="review-section">
            <div class="review-header">
                <h3>Personal Information</h3>
                <button type="button" class="btn-link" @onclick='() => OnEditSection.InvokeAsync(1)'>Edit</button>
            </div>
            <dl>
                <dt>Name</dt><dd>@Personal.FullName</dd>
                <dt>Email</dt><dd>@Personal.Email</dd>
                <dt>Phone</dt><dd>@Personal.Phone</dd>
                <dt>Address</dt><dd>@Personal.Address</dd>
            </dl>
        </div>

        <div class="review-section">
            <div class="review-header">
                <h3>Work History</h3>
                <button type="button" class="btn-link" @onclick='() => OnEditSection.InvokeAsync(2)'>Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="review-work-entry">
                    <strong>@entry.Title</strong> at <strong>@entry.Company</strong>
                    <br />
                    <span class="date-range">
                        @entry.StartDate?.ToString("MMM yyyy")
                        – @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="entry-description">@entry.Description</p>
                    }
                </div>
            }
        </div>

        <div class="review-section">
            <div class="review-header">
                <h3>References</h3>
                <button type="button" class="btn-link" @onclick='() => OnEditSection.InvokeAsync(3)'>Edit</button>
            </div>
            @foreach (var r in References)
            {
                <div class="review-reference">
                    <strong>@r.Name</strong> — @r.Relationship
                    <br />
                    <span>@r.Email · @r.Phone</span>
                </div>
            }
        </div>

        <div class="review-section">
            <div class="review-header">
                <h3>Cover Letter</h3>
                <button type="button" class="btn-link" @onclick='() => OnEditSection.InvokeAsync(4)'>Edit</button>
            </div>
            <p class="cover-letter-preview">@CoverLetter</p>
        </div>

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <p class="field-error">@errorMessage</p>
        }

        <div class="step-actions">
            <button type="button" class="btn-outline" @onclick="OnBack">Back</button>
            <button type="button" class="btn-primary btn-submit" @onclick="HandleSubmit" disabled="@isSubmitting">
                @if (isSubmitting)
                {
