.review-section {
    border: 1px solid #e2e8f0;
    border-radius: 0.5rem;
    padding: 1rem 1.25rem;
    margin-bottom: 1rem;
    background: #f8fafc;
}

.review-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.5rem;
}

.review-header h3 {
    margin: 0;
    font-size: 1rem;
    color: #1e293b;
}

.btn-link {
    background: none;
    border: none;
    color: #2563eb;
    cursor: pointer;
    font-size: 0.85rem;
    text-decoration: underline;
    padding: 0;
}

.btn-link:hover {
    color: #1d4ed8;
}

dl {
    display: grid;
    grid-template-columns: 6rem 1fr;
    gap: 0.25rem 1rem;
    margin: 0;
}

dt {
    font-weight: 600;
    color: #475569;
    font-size: 0.9rem;
}

dd {
    margin: 0;
    color: #1e293b;
    font-size: 0.9rem;
}

.review-work-entry,
.review-reference {
    padding: 0.5rem 0;
    border-bottom: 1px solid #e2e8f0;
    font-size: 0.9rem;
}

.review-work-entry:last-child,
.review-reference:last-child {
    border-bottom: none;
}

.date-range {
    color: #64748b;
    font-size: 0.85rem;
}

.entry-description {
    color: #475569;
    margin: 0.25rem 0 0;
    font-size: 0.85rem;
}

.cover-letter-preview {
    white-space: pre-wrap;
    color: #334155;
    font-size: 0.9rem;
    margin: 0;
}

.confirmation {
    text-align: center;
    padding: 2rem;
}

.confirmation-icon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 3.5rem;
    height: 3.5rem;
    background: #16a34a;
    color: #fff;
    border-radius: 50%;
    font-size: 1.8rem;
    margin-bottom: 1rem;
}

.confirmation h3 {
    color: #16a34a;
    margin-bottom: 0.5rem;
}

.btn-submit {
    min-width: 10rem;
}

