arguments.file_text:
@page "/apply"
@using sv_92875868f74646c48509ae444c691bd9.Components.JobApplication
@using sv_92875868f74646c48509ae444c691bd9.Models
@using sv_92875868f74646c48509ae444c691bd9.Services
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-container">
    <h1>Job Application</h1>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 1:
            <PersonalInfoStep Model="personalInfo"
                              ValidateEmail="ApplicationService.ValidateEmailAsync"
                              OnNext="() => CompleteAndAdvance(1)" />
            break;
        case 2:
            <WorkHistoryStep Entries="workEntries"
                             OnBack="() => GoToStep(1)"
                             OnNext="() => CompleteAndAdvance(2)" />
            break;
        case 3:
            <ReferencesStep References="references"
                            OnBack="() => GoToStep(2)"
                            OnNext="() => CompleteAndAdvance(3)" />
            break;
        case 4:
            <CoverLetterStep @bind-CoverLetter="coverLetter"
                             OnBack="() => GoToStep(3)"
                             OnNext="() => CompleteAndAdvance(4)" />
            break;
        case 5:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="coverLetter"
                        IsSubmitted="isSubmitted"
                        ApplicationId="applicationId"
                        OnEditSection="GoToStep"
                        OnBack="() => GoToStep(4)"
                        OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = [];
    private bool isSubmitted;
    private int applicationId;

    // Form state
    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = [new()];
    private List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";

    private void GoToStep(int step)
    {
        if (step == currentStep || isSubmitted) return;
        if (completedSteps.Contains(step) || step == currentStep)
            currentStep = step;
    }

    private void CompleteAndAdvance(int step)
    {
        completedSteps.Add(step);
        currentStep = step + 1;
    }

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            personalInfo.ToRecord(),
            new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
            references.Select(r => r.ToRecord()).ToList(),
            coverLetter
        );

        applicationId = await ApplicationService.SubmitApplicationAsync(application);
        isSubmitted = true;
    }
}

.apply-container {
    max-width: 48rem;
    margin: 0 auto;
    padding: 2rem 1rem;
}

.apply-container h1 {
    text-align: center;
    margin-bottom: 1.5rem;
    color: #1e293b;
}

/* Shared form styles used by step components (scoped via ::deep) */
::deep .step-section h2 {
    font-size: 1.25rem;
    color: #1e293b;
    margin-bottom: 1.25rem;
    padding-bottom: 0.5rem;
    border-bottom: 2px solid #e2e8f0;
}

::deep .form-group {
    margin-bottom: 1rem;
}

::deep .form-group label {
    display: block;
    font-weight: 500;
    color: #334155;
    margin-bottom: 0.3rem;
    font-size: 0.9rem;
}

::deep .form-group input[type="text"],
::deep .form-group input[type="email"],
::deep .form-group input[type="tel"],
::deep .form-group input[type="date"],
::deep .form-group textarea {
    width: 100%;
    padding: 0.55rem 0.75rem;
    border: 1px solid #cbd5e1;
    border-radius: 0.375rem;
    font-size: 0.9rem;
    transition: border-color 0.15s;
    box-sizing: border-box;
}

::deep .form-group input:focus,
::deep .form-group textarea:focus {
    outline: none;
    border-color: #2563eb;
    box-shadow: 0 0 0 2px rgba(37, 99, 235, 0.15);
}

::deep .form-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 1rem;
}

::deep .required {
    color: #dc2626;
}

::deep .field-error {
    color: #dc2626;
    font-size: 0.82rem;
    margin-top: 0.2rem;
    display: block;
}

::deep .validating-message {
    color: #2563eb;
    font-size: 0.85rem;
    font-style: italic;
