@using sv_92875868f74646c48509ae444c691bd9.Components.JobApplication
@using sv_92875868f74646c48509ae444c691bd9.Models
@using sv_92875868f74646c48509ae444c691bd9.Services
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-container">
    <h1>Job Application</h1>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 1:
            <PersonalInfoStep Model="personalInfo"
                              ValidateEmail="ApplicationService.ValidateEmailAsync"
                              OnNext="() => CompleteAndAdvance(1)" />
            break;
        case 2:
            <WorkHistoryStep Entries="workEntries"
                             OnBack="() => GoToStep(1)"
                             OnNext="() => CompleteAndAdvance(2)" />
            break;
        case 3:
            <ReferencesStep References="references"
                            OnBack="() => GoToStep(2)"
                            OnNext="() => CompleteAndAdvance(3)" />
            break;
        case 4:
            <CoverLetterStep @bind-CoverLetter="coverLetter"
                             OnBack="() => GoToStep(3)"
                             OnNext="() => CompleteAndAdvance(4)" />
            break;
        case 5:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="coverLetter"
                        IsSubmitted="isSubmitted"
                        ApplicationId="applicationId"
                        OnEditSection="GoToStep"
                        OnBack="() => GoToStep(4)"
                        OnSubmit="SubmitApplication" />
