using sv_92875868f74646c48509ae444c691bd9.Models;

namespace sv_92875868f74646c48509ae444c691bd9.Services;

/// <summary>Default implementation for demo/dev purposes.</summary>
public class DefaultApplicationService : IApplicationService
{
    private static int _nextId = 1000;

    public async Task<int> SubmitApplicationAsync(JobApplication application)
    {
        // Simulate network latency
        await Task.Delay(800);
        return Interlocked.Increment(ref _nextId);
    }

    public async Task<bool> ValidateEmailAsync(string email)
    {
        await Task.Delay(300);
        return !string.IsNullOrWhiteSpace(email) && email.Contains('@') && email.Contains('.');
    }
}

